SELECT region, cases
FROM case_distributions
WHERE cases > 100;

SELECT state_id, state_name, state_postal, population_density
FROM states
WHERE state_id > 10 AND population_density > 200;

SELECT state_name 
FROM states 
WHERE population_density = (SELECT MAX(population_density) FROM states);

SELECT advisory_text 
FROM health_advisories
WHERE julianday(expiry_date) - julianday(date('now')) <= 15;

SELECT AVG(total_cases) AS average_cases
FROM (
  SELECT state_id, SUM(cases) AS total_cases
  FROM case_data
  GROUP BY state_id
);

SELECT SUM(active_cases) AS total_active_cases
FROM case_data
WHERE state_id = 1 AND as_of = '2022-10-03';

SELECT cases
FROM case_data
WHERE state_id = 0;

SELECT state_id, AVG(active_cases) AS AverageActiveCases
FROM case_data
GROUP BY state_id;
